def alternating_case_generator(string):
    for i, char in enumerate(string):
        if i % 2 == 0:
            yield char.lower()
        else:
            yield char.upper()

if __name__ == "__main__":
    input_string = input().strip()
    result = alternating_case_generator(input_string)
    print("".join(result))
